query:
INSERT INTO news_items (title, source, summary, fullContent, category, url, publishedDate, status, feedSource) VALUES
('The Great Reinvention of Human Resources Has Begun', 'Josh Bersin', 'Human Resources is undergoing a massive, AI-driven reinvention starting in 2026, shifting from administrative overhead to a strategic, full-stack model. AI is transforming HR processes by automating tactical tasks and enabling HR professionals to focus on strategic initiatives that impact business value.', 'Human Resources (HR) is undergoing a massive, AI-driven reinvention starting in 2026, shifting from administrative overhead to a strategic, full-stack model. AI is transforming HR processes by automating tactical tasks, creating Superagents, and enabling HR professionals to focus on strategic initiatives that impact business value. The shift aims to improve scalability, accuracy, and trust in HR operations. Key insights include: HR roles will become more full-stack, focusing on talent acquisition, strategic talent management, culture, organization design, and AI orchestration. The HR employee-to-staff ratio could increase from 100:1 to 200:1, 300:1, or even 400:1. Data quality, explainability, and trust in AI systems are critical, with HR responsible for ensuring system integrity and managing AI bias.', 'HR Transformation', 'https://joshbersin.com/2026/01/the-great-reinvention-of-human-resources-has-begun/', '2026-01-24 00:00:00', 'approved', 'Manual Addition'),
('The Future of Work in 2026: 7 AI Trends and the Workplace Signals You Cannot Ignore', 'Eclectik', 'Microsofts 7 AI trends for 2026 reveal a future where AI becomes a full-fledged partner in work. The key to success lies in understanding and leveraging Workplace Signals - combining objective telemetry with subjective sentiment to build actionable AI roadmaps.', 'Microsoft recently offered a glimpse into the future with their 7 AI trends for 2026. These trends paint a picture where AI is no longer just a tool, but a full-fledged partner in work. Three key trends stand out: 1) AI as a Collaborator - amplifying humans rather than replacing them, 2) Secure and Trustworthy AI Agents - building the foundation of trust, and 3) AI in the Workflow - providing intelligence with context. The common thread is the need to understand and steer AIs impact through Workplace Signals. Eclectik operationalizes these signals end-to-end, combining objective telemetry with subjective sentiment to build actionable roadmaps that deliver measurable impact.', 'AI Trends', 'https://www.eclectik.co/insights/future-of-work-2026', '2026-01-26 00:00:00', 'approved', 'Manual Addition');

